t.script:

document.addEventListener("DOMContentLoaded", function () {
    const modal = document.getElementById("nx_ticket_attachment_modal");
    if (!modal) {
        return;
    }
    const modalBody = modal.querySelector(".nx-ticket-attachment-modal-body");
    const modalTitle = modal.querySelector(".nx-ticket-attachment-modal-title");
    const closeButton = modal.querySelector(".nx-ticket-attachment-modal-close");
    const attachmentButtons = document.querySelectorAll(".nx-ticket-attachment-link[data-preview-url]");

    const closeModal = function () {
        modal.classList.remove("is-open");
        modal.setAttribute("aria-hidden", "true");
        modalBody.innerHTML = "";
    };

    attachmentButtons.forEach(function (button) {
        button.addEventListener("click", function () {
            const previewUrl = button.dataset.previewUrl;
            const mimetype = button.dataset.mimetype || "";
            const name = button.dataset.name || "Attachment";
            modalTitle.textContent = name;
            if (mimetype.startsWith("image/")) {
                modalBody.innerHTML = '<img class="nx-ticket-attachment-modal-image" src="' + previewUrl + '" alt="' + name + '"/>';
            } else {
                modalBody.innerHTML = '<iframe class="nx-ticket-attachment-modal-frame" src="' + previewUrl + '" title="' + name + '"></iframe>';
            }
            modal.classList.add("is-open");
            modal.setAttribute("aria-hidden", "false");
        });
    });

    closeButton.addEventListener("click", closeModal);
    modal.addEventListener("click", function (event) {
        if (event.target === modal) {
            closeModal();
        }
    });
    document.addEventListener("keydown", function (event) {
        if (event.key === "Escape" && modal.classList.contains("is-open")) {
            closeModal();
        }
    });
});

div.script:

document.addEventListener("DOMContentLoaded", function () {
    const teamSelect = document.getElementById("nx_ticket_team_select");
    const teamLabel = document.getElementById("nx_ticket_selected_team_label");
    if (!teamSelect || !teamLabel) {
        return;
    }

    const syncSelectedTeamLabel = function () {
        const selectedOption = teamSelect.options[teamSelect.selectedIndex];
        if (selectedOption) {
            teamLabel.textContent = selectedOption.textContent.trim();
        }
    };

    teamSelect.addEventListener("change", syncSelectedTeamLabel);
    syncSelectedTeamLabel();
});
